import{_ as e,a as d,b as o,c as a,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as l,o as c,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Other/ocr.md","filePath":"ar-SA/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"ar-SA/Other/ocr.md"};function h(u,t,g,b,m,P){return c(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>تستخرج OCR النصوص من الصور، والملفات الممسوحة، ولقطات شاشة المستندات.</p><p>بعد التعرف يمكنك نسخ النتيجة، أو تصديرها بصيغة <code>Markdown</code> أو <code>PDF</code> أو <code>Word</code>، أو تجميع عدة صيغ في حزمة واحدة للتنزيل.</p><h2 id="ماذا-تستطيع-ocr-فعله؟" tabindex="-1">ماذا تستطيع OCR فعله؟ <a class="header-anchor" href="#ماذا-تستطيع-ocr-فعله؟" aria-label="Permalink to &quot;ماذا تستطيع OCR فعله؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الميزة</th><th>الوصف</th></tr></thead><tbody><tr><td>التعرف على نص الصور</td><td>استخراج النص من الصور ولقطات الشاشة والمسح الضوئي.</td></tr><tr><td>التعرف على تخطيط المستندات</td><td>أفضل للجداول والمعادلات والأختام والتخطيطات المختلطة بين النص والصورة.</td></tr><tr><td>خدمات متعددة</td><td>تدعم Baidu PaddleOCR و Microsoft Azure Vision و Google Vision.</td></tr><tr><td>نسخ النتائج</td><td>نسخ النص المتعرف عليه بعد المعالجة.</td></tr><tr><td>تصدير الملفات</td><td>تصدير <code>Markdown</code> و <code>PDF</code> و <code>Word</code>.</td></tr><tr><td>Batch packaging</td><td>بعد التعرف على عدة ملفات، يمكن تنزيل النتائج كحزمة.</td></tr></tbody></table><h2 id="اضبط-خدمات-ocr-أولًا" tabindex="-1">اضبط خدمات OCR أولًا <a class="header-anchor" href="#اضبط-خدمات-ocr-أولًا" aria-label="Permalink to &quot;اضبط خدمات OCR أولًا&quot;">​</a></h2><p>افتح:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+e+'" alt="IP geolocation و OCR" loading="lazy"></p><p>املأ بيانات الخدمات التي تريد استخدامها:</p><table tabindex="0"><thead><tr><th>الخدمة</th><th>ما الذي تدخله</th><th>أفضل استخدام</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>الخيار الأول الموصى به. مناسب للمستندات والصور والجداول والتخطيطات المختلطة.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> و <code>Azure Vision API Key</code></td><td>مناسب إذا كنت تستخدم خدمات Microsoft السحابية.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. يستخدم service account <code>JSON</code> فقط لاستعلام الحصة.</td><td>مناسب إذا كنت تستخدم Google Cloud.</td></tr></tbody></table><p>احفظ بعد إدخال البيانات.</p><p>يمكن ضبط خدمة واحدة فقط للتجربة الأولى. لا تحتاج إلى الثلاث كلها.</p><h2 id="إعداد-google-vision" tabindex="-1">إعداد Google Vision <a class="header-anchor" href="#إعداد-google-vision" aria-label="Permalink to &quot;إعداد Google Vision&quot;">​</a></h2><p>إعداد Google له جزآن:</p><table tabindex="0"><thead><tr><th>الهدف</th><th>المتطلب</th></tr></thead><tbody><tr><td>استخدام OCR</td><td>تفعيل <code>Cloud Vision API</code> ثم إنشاء <code>API Key</code>.</td></tr><tr><td>استعلام الاستخدام</td><td>إنشاء service account ومنحه <code>Monitoring Viewer</code> ثم تنزيل service account <code>JSON</code>.</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key و service account" loading="lazy"></p><h3 id="استخدام-google-للتعرف" tabindex="-1">استخدام Google للتعرف <a class="header-anchor" href="#استخدام-google-للتعرف" aria-label="Permalink to &quot;استخدام Google للتعرف&quot;">​</a></h3><ol><li>افتح Google Cloud Console.</li><li>انتقل إلى <code>APIs &amp; Services</code>.</li><li>افتح <code>Library</code> وابحث عن <code>Cloud Vision API</code> وفعّله.</li><li>ارجع إلى <code>Credentials</code>.</li><li>أنشئ <code>API Key</code>.</li><li>افتح API Key وانسخه.</li><li>الصقه في <code>Google Vision API Key</code> داخل ImgBed.</li><li>احفظ.</li></ol><p>بعد ذلك يمكنك اختيار Google Vision من نافذة OCR.</p><h3 id="استعلام-استخدام-google" tabindex="-1">استعلام استخدام Google <a class="header-anchor" href="#استعلام-استخدام-google" aria-label="Permalink to &quot;استعلام استخدام Google&quot;">​</a></h3><p>Quota query غير مطلوب للتعرف نفسه.</p><p>يعرض فقط تقريبًا عدد استدعاءات Google Vision المستخدمة خلال آخر 30 يومًا.</p><ol><li>في Google Cloud Console افتح <code>IAM &amp; Admin</code>.</li><li>افتح <code>Service Accounts</code>.</li><li>أنشئ service account، مثل <code>vision-monitor</code>.</li><li>امنحه دور <code>Monitoring Viewer</code>.</li><li>افتح تفاصيل service account وأنشئ key.</li><li>اختر <code>JSON</code>.</li><li>نزّل ملف JSON الناتج.</li><li>ارجع إلى ImgBed واستورده ضمن service account <code>JSON</code> (اختياري).</li><li>بعد نجاح الاستيراد اضغط quota query.</li></ol><p>بعد الاستيراد، يعرض ImgBed اسم المشروع الذي يملك service account. عند الاستعلام يقرأ ImgBed بيانات Google monitoring ويعرض عدد استدعاءات هذا الشهر.</p><p>باختصار:</p><table tabindex="0"><thead><tr><th>العنصر</th><th>الغرض</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>تنفيذ التعرف OCR.</td></tr><tr><td>Service account <code>JSON</code></td><td>معرفة عدد استدعاءات Google Vision المستخدمة.</td></tr><tr><td>دور <code>Monitoring Viewer</code></td><td>يسمح للحساب الخدمي بقراءة بيانات الاستخدام.</td></tr></tbody></table><h2 id="الحصول-على-baidu-paddleocr-token" tabindex="-1">الحصول على Baidu PaddleOCR Token <a class="header-anchor" href="#الحصول-على-baidu-paddleocr-token" aria-label="Permalink to &quot;الحصول على Baidu PaddleOCR Token&quot;">​</a></h2><p>يتطلب Baidu PaddleOCR access token.</p><p><img src="'+d+'" alt="الحصول على PaddleOCR token" loading="lazy"></p><p>افتح نافذة استدعاء <code>API</code> في صفحة Baidu PaddleOCR، واضغط للحصول على token، ثم انسخه.</p><p>ارجع إلى ImgBed، والصقه في <code>PaddleOCR Token</code>، واحفظ.</p><h2 id="بدء-التعرف" tabindex="-1">بدء التعرف <a class="header-anchor" href="#بدء-التعرف" aria-label="Permalink to &quot;بدء التعرف&quot;">​</a></h2><p>في File Management اختر صورة أو لقطة شاشة لمستند واضغط <code>OCR</code>.</p><p><img src="'+o+'" alt="تعرف OCR" loading="lazy"></p><p>في النافذة اختر خدمة التعرف والنموذج.</p><p>نماذج PaddleOCR الشائعة:</p><table tabindex="0"><thead><tr><th>Model</th><th>أفضل استخدام</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>الافتراضي الموصى به. جيد للمستندات والجداول والمعادلات والأختام والتخطيطات المختلطة.</td></tr><tr><td><code>PP-OCRv5</code></td><td>صور بسيطة ونصوص عادية وتعرف خفيف.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>صور معقدة ومتعددة اللغات ومحتوى يشبه الرسوم البيانية.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>صفحات مستندات أكثر تعقيدًا واسترجاع التخطيط.</td></tr></tbody></table><p>إذا لم تكن متأكدًا، ابدأ بـ <code>PP-StructureV3</code>.</p><h2 id="خيارات-متقدمة" tabindex="-1">خيارات متقدمة <a class="header-anchor" href="#خيارات-متقدمة" aria-label="Permalink to &quot;خيارات متقدمة&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الخيار</th><th>الوصف</th></tr></thead><tbody><tr><td>Orientation correction</td><td>استخدمه عند دوران الصورة أو ميلانها.</td></tr><tr><td>Document flattening</td><td>للوثائق المصورة التي فيها انحناء أو ميل.</td></tr><tr><td>Layout detection</td><td>عند الرغبة في حفظ العناوين والفقرات والجداول وبنية الصور.</td></tr><tr><td>Chart recognition</td><td>عند وجود رسوم بيانية أو بنى معقدة.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>يجعل Markdown الناتج أسهل قراءة.</td></tr></tbody></table><p>للقطات الشاشة العادية اترك الخيارات قليلة. للمسح الضوئي للوثائق فعّل خيارات المستندات أكثر.</p><h2 id="عرض-النتائج" tabindex="-1">عرض النتائج <a class="header-anchor" href="#عرض-النتائج" aria-label="Permalink to &quot;عرض النتائج&quot;">​</a></h2><p>بعد انتهاء التعرف تعرض النافذة النتيجة.</p><p>يمكنك نسخها مباشرة أو اختيار صيغ التصدير.</p><p><img src="'+a+'" alt="تعرف PDF" loading="lazy"></p><p>في صفحات المستندات، يمكن لـ <code>PDF</code> الناتج الحفاظ على شكل الصفحة مع إبقاء النص قابلًا للبحث. هذا مفيد لأرشفة المسح الضوئي والبحث لاحقًا.</p><h2 id="اختيار-صيغة-التصدير" tabindex="-1">اختيار صيغة التصدير <a class="header-anchor" href="#اختيار-صيغة-التصدير" aria-label="Permalink to &quot;اختيار صيغة التصدير&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الصيغة</th><th>أفضل استخدام</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>الملاحظات وأنظمة التوثيق والتحرير اللاحق.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>حفظ شكل الصفحة ونتائج المستندات الممسوحة.</td></tr><tr><td><code>Word (.docx)</code></td><td>متابعة تحرير التخطيط والنص وتسليمه للآخرين.</td></tr><tr><td>Export all</td><td>حفظ عدة صيغ مع الصورة الأصلية، مناسب للأرشيف المهم.</td></tr></tbody></table><p>إذا كنت تحتاج النص فقط، صدّر Markdown.</p><p>إذا كان شكل الصفحة مهمًا، استخدم PDF أو Word.</p><h2 id="إخراج-word" tabindex="-1">إخراج Word <a class="header-anchor" href="#إخراج-word" aria-label="Permalink to &quot;إخراج Word&quot;">​</a></h2><p>يمكن فتح مستندات Word الناتجة وتعديلها ببرامج المكتب.</p><p><img src="'+r+`" alt="نتيجة Word" loading="lazy"></p><p>بعض المستندات تتضمن صورًا وعناوين وفقرات متعرفًا عليها داخل Word output.</p><p>تعتمد جودة التعرف على وضوح الصورة الأصلية، واختيار النموذج، وتعقيد المستند.</p><h2 id="أفضل-أنواع-الملفات-لـ-ocr" tabindex="-1">أفضل أنواع الملفات لـ OCR <a class="header-anchor" href="#أفضل-أنواع-الملفات-لـ-ocr" aria-label="Permalink to &quot;أفضل أنواع الملفات لـ OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>نوع الملف</th><th>التوصية</th></tr></thead><tbody><tr><td>لقطات شاشة واضحة</td><td>تعرّف عليها مباشرة.</td></tr><tr><td>ملفات ممسوحة</td><td>فضّل <code>PP-StructureV3</code>.</td></tr><tr><td>مستندات مصورة</td><td>فعّل orientation correction و document flattening.</td></tr><tr><td>جداول ومعادلات وأختام</td><td>فضّل structured models.</td></tr><tr><td>صور نصوص قصيرة بسيطة</td><td>غالبًا يكفي <code>PP-OCRv5</code>.</td></tr></tbody></table><p>الصور الأوضح والنصوص الأكثر استقامة تعطي نتائج أفضل عادة.</p><h2 id="حالات-شائعة" tabindex="-1">حالات شائعة <a class="header-anchor" href="#حالات-شائعة" aria-label="Permalink to &quot;حالات شائعة&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الحالة</th><th>المعنى</th></tr></thead><tbody><tr><td>Recognition fails</td><td>تحقق من حفظ service token أو key.</td></tr><tr><td>Recognition is slow</td><td>المستندات المعقدة والصور الكبيرة تستغرق وقتًا أطول.</td></tr><tr><td>Table is incomplete</td><td>جرّب نموذجًا هيكليًا.</td></tr><tr><td>Text has mistakes</td><td>الضبابية واللمعان والميل تزيد الأخطاء. جرّب صورة أوضح.</td></tr><tr><td>Word output contains many images</td><td>قد تحفظ structured models بعض الصور المتعرف عليها. هذا طبيعي.</td></tr></tbody></table><h3 id="فشل-google-quota-query" tabindex="-1">فشل Google Quota Query <a class="header-anchor" href="#فشل-google-quota-query" aria-label="Permalink to &quot;فشل Google Quota Query&quot;">​</a></h3><p>تحقق من:</p><ol><li>تم استيراد service account <code>JSON</code>.</li><li>لدى service account دور <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> مفعّل للمشروع.</li></ol><p>إذا كنت تحتاج OCR فقط ولا تحتاج استعلام الاستخدام، يمكنك تجاهل service account JSON وملء <code>Google Vision API Key</code> فقط.</p><h2 id="المسار-السريع" tabindex="-1">المسار السريع <a class="header-anchor" href="#المسار-السريع" aria-label="Permalink to &quot;المسار السريع&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>افتح System Settings</span></span>
<span class="line"><span>-&gt; افتح Other Settings</span></span>
<span class="line"><span>-&gt; املأ بيانات خدمات OCR</span></span>
<span class="line"><span>-&gt; احفظ</span></span>
<span class="line"><span>-&gt; ارجع إلى File Management</span></span>
<span class="line"><span>-&gt; اختر ملفًا واضغط OCR</span></span>
<span class="line"><span>-&gt; اختر نموذجًا</span></span>
<span class="line"><span>-&gt; انتظر التعرف</span></span>
<span class="line"><span>-&gt; انسخ النتائج أو صدّر Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const q=l(p,[["render",h]]);export{k as __pageData,q as default};
